class i{prefix="/api/action";selectAll=async()=>{const e=new Request(`undefined${this.prefix}`);return await(await fetch(e)).json()};selectOne=async e=>{const s=new Request(`undefined${this.prefix}/${e}`);return await(await fetch(s)).json()};insert=async(e,s)=>{const t=new Request(`undefined${this.prefix}`,{method:"post",body:e,headers:{Authorization:`Bearer ${s}`}});return await(await fetch(t)).json()};update=async(e,s)=>{const t=new Request(`undefined${this.prefix}`,{method:"put",body:e,headers:{Authorization:`Bearer ${s}`}});return await(await fetch(t)).json()};delete=async(e,s)=>{const t=new Request(`undefined${this.prefix}`,{method:"delete",headers:{"Content-Type":"application/json",Authorization:`Bearer ${s}`},body:JSON.stringify(e)});return await(await fetch(t)).json()}}export{i as A};
